// Uunimaentie 1, Vantaa — 1970s rivitalo (row house), 4 units
// Long rectangular footprint ~28x8m, 2 stories, brick facade, tile roof

// Foundation
const foundation = translate(cube({size: [28, 0.35, 8], center: true}), [0, 0.175, 0]);

// Ground floor walls
const gf_front = translate(cube({size: [28, 2.7, 0.25], center: true}), [0, 1.7, -3.875]);
const gf_back = translate(cube({size: [28, 2.7, 0.25], center: true}), [0, 1.7, 3.875]);
const gf_left = translate(cube({size: [0.25, 2.7, 8], center: true}), [-13.875, 1.7, 0]);
const gf_right = translate(cube({size: [0.25, 2.7, 8], center: true}), [13.875, 1.7, 0]);

// Unit dividing walls (3 dividers for 4 units, each ~7m wide)
const div1 = translate(cube({size: [0.2, 2.7, 8], center: true}), [-7, 1.7, 0]);
const div2 = translate(cube({size: [0.2, 2.7, 8], center: true}), [0, 1.7, 0]);
const div3 = translate(cube({size: [0.2, 2.7, 8], center: true}), [7, 1.7, 0]);

// Front doors (one per unit)
const door1 = translate(cube({size: [1.0, 2.1, 0.35], center: true}), [-10.5, 1.4, -3.875]);
const door2 = translate(cube({size: [1.0, 2.1, 0.35], center: true}), [-3.5, 1.4, -3.875]);
const door3 = translate(cube({size: [1.0, 2.1, 0.35], center: true}), [3.5, 1.4, -3.875]);
const door4 = translate(cube({size: [1.0, 2.1, 0.35], center: true}), [10.5, 1.4, -3.875]);
const gf_front_cut = difference(difference(difference(difference(gf_front, door1), door2), door3), door4);

// Front windows (two per unit)
const fw = [];
const fwPositions = [-12.5, -8.5, -5.5, -1.5, 1.5, 5.5, 8.5, 12.5];
let gf_front_final = gf_front_cut;
for (let i = 0; i < fwPositions.length; i++) {
  const w = translate(cube({size: [1.2, 1.3, 0.35], center: true}), [fwPositions[i], 1.8, -3.875]);
  gf_front_final = difference(gf_front_final, w);
}

// Back windows and terrace doors
let gf_back_final = gf_back;
const bwPositions = [-11.5, -8.0, -4.5, -1.0, 1.0, 4.5, 8.0, 11.5];
for (let i = 0; i < bwPositions.length; i++) {
  const w = translate(cube({size: [1.4, 1.3, 0.35], center: true}), [bwPositions[i], 1.8, 3.875]);
  gf_back_final = difference(gf_back_final, w);
}

// First floor slab
const floor1 = translate(cube({size: [28, 0.25, 8], center: true}), [0, 3.175, 0]);

// Upper floor walls
const uf_front = translate(cube({size: [28, 2.7, 0.25], center: true}), [0, 4.65, -3.875]);
const uf_back = translate(cube({size: [28, 2.7, 0.25], center: true}), [0, 4.65, 3.875]);
const uf_left = translate(cube({size: [0.25, 2.7, 8], center: true}), [-13.875, 4.65, 0]);
const uf_right = translate(cube({size: [0.25, 2.7, 8], center: true}), [13.875, 4.65, 0]);

// Upper dividers
const udiv1 = translate(cube({size: [0.2, 2.7, 8], center: true}), [-7, 4.65, 0]);
const udiv2 = translate(cube({size: [0.2, 2.7, 8], center: true}), [0, 4.65, 0]);
const udiv3 = translate(cube({size: [0.2, 2.7, 8], center: true}), [7, 4.65, 0]);

// Upper floor windows
let uf_front_final = uf_front;
for (let i = 0; i < fwPositions.length; i++) {
  const w = translate(cube({size: [1.1, 1.1, 0.35], center: true}), [fwPositions[i], 4.7, -3.875]);
  uf_front_final = difference(uf_front_final, w);
}

let uf_back_final = uf_back;
for (let i = 0; i < bwPositions.length; i++) {
  const w = translate(cube({size: [1.1, 1.1, 0.35], center: true}), [bwPositions[i], 4.7, 3.875]);
  uf_back_final = difference(uf_back_final, w);
}

// Gable roof — 25deg pitch, tile look
const roof_left = translate(rotate(cube({size: [28.8, 0.1, 5.2], center: true}), [0.44, 0, 0]), [0, 7.4, -2.2]);
const roof_right = translate(rotate(cube({size: [28.8, 0.1, 5.2], center: true}), [-0.44, 0, 0]), [0, 7.4, 2.2]);

scene = union(
  foundation,
  gf_front_final, gf_back_final, gf_left, gf_right,
  div1, div2, div3,
  floor1,
  uf_front_final, uf_back_final, uf_left, uf_right,
  udiv1, udiv2, udiv3,
  roof_left, roof_right
);
